const item = $input.first().json;
const assetId = item.id || $('Loop one at a time').item.json.new_items;
const filename = item.originalFileName || item.originalPath || 'unknown';
const createdAt = item.fileCreatedAt || item.localDateTime || '';
const exif = item.exifInfo || {};
const city = exif.city || '';
const country = exif.country || '';
const location = [city, country].filter(Boolean).join(', ');

const dateStr = createdAt ? new Date(createdAt).toISOString().slice(0, 10) : '';

const lines = [
  '<b>New Immich candidate</b>',
  '',
  '<code>' + assetId + '</code>',
  '',
  '<b>File:</b> ' + filename
];
if (dateStr) lines.push('<b>Taken:</b> ' + dateStr);
if (location) lines.push('<b>Where:</b> ' + location);
lines.push('');
lines.push('Approve to enqueue for posting, reject to mark seen.');

return [{ json: { asset_id: assetId, caption: lines.join('\n') } }];
